#!/usr/bin/env node
/**
 * Generate `lib/recipes/screens.generated.ts` — a typed lazy-import map
 * of every built-in React recipe under `app/(app)/recipes/screens/`.
 *
 * Each entry imports the recipe module and returns its `definition` export.
 * Recipes without a `definition` export are still indexed (the loader will
 * throw at runtime), so missing definitions surface as a real error instead
 * of silently dropping the recipe from the catalog.
 *
 * The generated file is committed (matches the pattern of
 * `lib/database/db.d.ts` and `lib/trmnl/types.gen.ts`).
 */
import { readdirSync, statSync, writeFileSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(__dirname, "..");
const screensDir = join(repoRoot, "app", "(app)", "recipes", "screens");
const outFile = join(repoRoot, "lib", "recipes", "screens.generated.ts");

function listRecipeSlugs() {
	const entries = readdirSync(screensDir);
	const slugs = [];
	for (const entry of entries) {
		const abs = join(screensDir, entry);
		if (!statSync(abs).isDirectory()) continue;
		// A recipe directory must contain `<slug>.tsx`.
		try {
			statSync(join(abs, `${entry}.tsx`));
			slugs.push(entry);
		} catch {
			// Skip directories without a matching component file.
		}
	}
	slugs.sort();
	return slugs;
}

function buildSource(slugs) {
	const header = `// This file is auto-generated by scripts/generate-recipes-index.mjs.
// Do not edit by hand. Run \`pnpm generate:recipes\` to regenerate.
import type { RecipeModuleLoader } from "./types";

`;

	const entries = slugs
		.map((slug) => {
			// Path relative to lib/recipes/screens.generated.ts
			// → ../../app/(app)/recipes/screens/<slug>/<slug>
			const importPath = `../../app/(app)/recipes/screens/${slug}/${slug}`;
			return `\t"${slug}": () => import("${importPath}"),`;
		})
		.join("\n");

	const slugsList = slugs.map((s) => `\t"${s}",`).join("\n");

	return `${header}export const reactRecipeLoaders: Record<string, RecipeModuleLoader> = {
${entries}
};

export const reactRecipeSlugs = [
${slugsList}
] as const;

export type ReactRecipeSlug = (typeof reactRecipeSlugs)[number];
`;
}

const slugs = listRecipeSlugs();
const source = buildSource(slugs);
writeFileSync(outFile, source, "utf8");

console.log(
	`[generate-recipes-index] Wrote ${slugs.length} recipes to ${outFile}`,
);
